package arch.day60;

public class Day60FresherExercise {
    public static void main(String[] args) {
        // This title tells the learner the program is a reference card for week one.
        System.out.println("=== Producer safety card ===");
        // This line explains the fastest and least safe write mode.
        System.out.println("acks=0 -> no broker confirmation, possible silent loss");
        // This line explains the middle durability option.
        System.out.println("acks=1 -> leader confirms, still has follower loss window");
        // This line explains strongest common durability mode.
        System.out.println("acks=all -> ISR confirms write before success");
        // This line teaches retry duplicate protection in plain language.
        System.out.println("idempotence -> prevents duplicate writes from retry path");
        // This line teaches the ordering rule that beginners miss first.
        System.out.println("stable key -> keeps one entity on one partition order");
        // This line gives an actionable command for durability verification.
        System.out.println("command -> kafka-topics.sh --describe --topic orders.events");
        // This line tells what to inspect in command output.
        System.out.println("check -> ISR count is healthy for your durability policy");
        // This final line reinforces the full safety contract.
        System.out.println("remember -> key + acks + idempotence + ISR health");
    }
}

package arch.day60;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;

public class Day60StaffExercise {
    // Staff reasoning starts with explicit data model for decision traceability.
    record Topic(String name, boolean critical, int p99BudgetMs) {}
    // Each policy row includes rationale so reviewers can challenge assumptions.
    record Policy(String topic, String acks, boolean idempotence, int lingerMs, int timeoutMs, String why) {}

    public static void main(String[] args) {
        // Build deterministic context used in design review and on-call handoff.
        List<Topic> topics = List.of(
            new Topic("payments.events", true, 120),
            new Topic("orders.events", true, 200),
            new Topic("analytics.events", false, 800)
        );

        // Apply policy function so similar topics receive consistent settings.
        List<Policy> policies = new ArrayList<>();
        for (Topic t : topics) {
            if (t.critical()) {
                policies.add(new Policy(t.name(), "all", true, 5, 45000, "critical flow durability"));
            } else {
                policies.add(new Policy(t.name(), "1", true, 15, 30000, "throughput-oriented replayable flow"));
            }
        }

        // Print recommendation table that teams can use directly.
        System.out.println("=== Producer policy table ===");
        for (Policy p : policies) {
            System.out.println(p.topic() + " | acks=" + p.acks() + " | idem=" + p.idempotence()
                + " | linger=" + p.lingerMs() + " | timeout=" + p.timeoutMs() + " | " + p.why());
        }

        // Print first commands per symptom so incident response is immediate.
        System.out.println("=== Triage commands ===");
        Map<String, String> triage = Map.of(
            "NotEnoughReplicasException", "kafka-topics.sh --describe --topic payments.events",
            "TimeoutException", "kafka-producer-perf-test.sh --topic payments.events --num-records 10000",
            "High GC pause", "jstat -gcutil <pid> 1s 10"
        );
        for (Map.Entry<String, String> e : triage.entrySet()) {
            System.out.println(e.getKey() + " -> " + e.getValue());
        }

        // This guardrail prevents unsafe overrides from entering production unnoticed.
        System.out.println("guardrail -> CI blocks critical topics without acks=all and idempotence=true");
        // This success criterion keeps post-deploy verification objective.
        System.out.println("success -> duplicate side effects zero and timeout rate reduced");
    }
}

